    /// AC-VDOT-NAME-04: 說明頁不提徐國峰 / 跑力 / RQ / runningquotient
    func test_ac_vdot_name_04_no_competitor_mention_in_description() throws {
        let forbiddenTerms = ["徐國峰", "RQ", "runningquotient", "Runningquotient"]
        for locale in ["zh-Hant", "en", "ja"] {
            let desc = LocalizedString.lookup(key: "performance.vdot.vdot_description", locale: locale)
            for term in forbiddenTerms {
                XCTAssertFalse(
                    desc.contains(term),
                    "vdot_description in \(locale) must not contain '\(term)'; got: \(desc)"
                )
            }
            // zh-Hant 還要排除單獨「跑力」（但允許「動態跑力」）
            if locale == "zh-Hant" {
                let withoutDynamic = desc.replacingOccurrences(of: "動態跑力", with: "")
                XCTAssertFalse(
                    withoutDynamic.contains("跑力"),
                    "zh-Hant vdot_description must not contain '跑力' outside '動態跑力'; got: \(desc)"
                )
            }
        }
    }

    /// AC-VDOT-NAME-04b: 說明頁底部官網連結 key 存在且為合法 URL
    func test_ac_vdot_name_04b_blog_link_present_and_valid() throws {
        for locale in ["zh-Hant", "en", "ja"] {
            let urlString = LocalizedString.lookup(key: "performance.vdot.blog_url", locale: locale)
            XCTAssertFalse(urlString.isEmpty, "blog_url in \(locale) must not be empty")
            XCTAssertNotNil(URL(string: urlString), "blog_url in \(locale) must be valid URL: \(urlString)")
            XCTAssertTrue(
                urlString.hasPrefix("https://paceriz.com/blog/"),
                "blog_url in \(locale) must point to paceriz.com/blog/; got: \(urlString)"
            )
            // read_more label key 存在
            let readMore = LocalizedString.lookup(key: "performance.vdot.read_more", locale: locale)
            XCTAssertFalse(readMore.isEmpty, "read_more label in \(locale) must not be empty")
        }
    }

    /// AC-VDOT-NAME-05: zh-Hant strings 不可有「加權跑力」「最新跑力」殘留
    /// （Note: 編譯後 .strings 是 binary plist，需用 NSDictionary 讀；不可用 String(contentsOf:)）
    func test_ac_vdot_name_05_no_legacy_terms_in_zh_hant() throws {
        let forbidden = ["加權跑力", "最新跑力", "平均加權跑力", "最新動態跑力"]
        let bundle = Bundle.main
        guard let path = bundle.path(forResource: "zh-Hant", ofType: "lproj"),
              let localeBundle = Bundle(path: path),
              let stringsURL = localeBundle.url(forResource: "Localizable", withExtension: "strings"),
              let dict = NSDictionary(contentsOf: stringsURL) as? [String: String] else {
            XCTFail("無法讀取 zh-Hant Localizable.strings (binary plist)")
            return
        }
        for (key, value) in dict {
            for term in forbidden {
                XCTAssertFalse(
                    value.contains(term),
                    "zh-Hant strings key '\(key)' 不可含「\(term)」；got value: \(value)"
                )
            }
        }
    }

