// MARK: - Helper

private enum LocalizedString {
    /// 取指定 locale 的 strings 值；找不到回傳 key 本身（讓 test fail）。
    static func lookup(key: String, locale: String) -> String {
        let bundle = Bundle.main
        guard let path = bundle.path(forResource: locale, ofType: "lproj"),
              let localeBundle = Bundle(path: path) else {
            return key
        }
        return NSLocalizedString(key, bundle: localeBundle, comment: "")
    }
